param(
  [string]$SolutionPath,
  [string]$Configuration = "Debug"
)

# PowerShell script to run all test projects listed in a solution and produce combined coverage HTML
# Use the script folder as root (do not go to its parent)
$ErrorActionPreference = 'Continue'

# --- Helpers for sound and error UI ---
$script:LastSoundTime = $null

function Play-SoundFile {
  param(
    [string]$FilePath,
    [int]$MinIntervalSeconds = 5
  )
  if (-not $FilePath) { $FilePath = Join-Path $PSScriptRoot 'Windows Notify.wav' }

  $now = Get-Date
  if ($script:LastSoundTime) {
    $elapsed = ($now - $script:LastSoundTime).TotalSeconds
    if ($elapsed -lt $MinIntervalSeconds) {
      return $false
    }
  }

  if (Test-Path $FilePath) {
    try {
      $script:LastSoundTime = $now
      $player = New-Object System.Media.SoundPlayer $FilePath
      $player.PlaySync()
      return $true
    } catch {
      Write-Warning "Failed to play sound '$FilePath': $($_.Exception.Message)"
      return $false
    }
  } else {
    return $false
  }
}

function Emit-Beep {
  param(
    [int]$Frequency = 750,
    [int]$Duration = 220
  )
  # Preferir tocar um arquivo WAV (Windows Notify.wav) com debounce.
  $played = Play-SoundFile -FilePath (Join-Path $PSScriptRoot 'Windows Notify.wav') -MinIntervalSeconds 5
  if (-not $played) {
    try {
     # [console]::beep($Frequency, $Duration)
    } catch {
      # Fallback to BEL if console beep fails
      Write-Host "`a" -NoNewline
    }
  }
}

function Play-FinalRing {
  param(
    [string]$FilePath
  )
  if (-not $FilePath) { $FilePath = Join-Path $PSScriptRoot 'Ring01.wav' }
  $played = Play-SoundFile -FilePath $FilePath -MinIntervalSeconds 5
  if (-not $played) {
    Write-Warning "Sound file not found or failed: $FilePath"
    Emit-Beep -Frequency 900 -Duration 300
  }
}

function Open-ErrorCover {
  param(
    [string]$HtmlPath
  )
  if (-not $HtmlPath) { $HtmlPath = Join-Path $PSScriptRoot 'ErrorCover.html' }
  if (Test-Path $HtmlPath) {
    try {
      Start-Process -FilePath $HtmlPath
    } catch {
      Write-Warning "Failed to open error page: $($_.Exception.Message)"
      Emit-Beep -Frequency 400 -Duration 400
    }
  } else {
    Write-Warning "Error HTML file not found: $HtmlPath"
    Emit-Beep -Frequency 400 -Duration 400
  }
}
$root = $PSScriptRoot

# Run ClearCoverageXML.bat in the script folder (if present) and wait for it to finish
$clearBat = Join-Path $PSScriptRoot 'ClearCoverageXML.bat'
if (Test-Path $clearBat) {
  Write-Host "Running ClearCoverageXML.bat..."
  try {
    $proc = Start-Process -FilePath $clearBat -WorkingDirectory $PSScriptRoot -NoNewWindow -Wait -PassThru
    if ($proc.ExitCode -ne 0) {
      Write-Warning "ClearCoverageXML.bat exited with code $($proc.ExitCode)"
    } else {
      Write-Host "ClearCoverageXML.bat completed successfully."
    }
  } catch {
    Write-Warning "Failed to run ClearCoverageXML.bat: $($_.Exception.Message)"
  }
} else {
  Write-Host "ClearCoverageXML.bat not found; skipping cleanup."
}

if (-not $SolutionPath) {
  # Prefer a solution file located in the parent folder of the script,
  # then the script folder; finally fallback to a recursive search.
  $parent = Split-Path -Path $root -Parent

  # 1) parent folder candidate
  $candidateParent = Join-Path $parent 'GerAdv.slnx'
  if (Test-Path $candidateParent) {
    $SolutionPath = $candidateParent
  } else {
    # 2) script folder candidate
    $candidateScript = Join-Path $root 'GerAdv.slnx'
    if (Test-Path $candidateScript) {
      $SolutionPath = $candidateScript
    } else {
      # 3) fallback: first .slnx under parent (recursive), then under script folder
      $first = Get-ChildItem -Path $parent -Recurse -Filter *.slnx -File -ErrorAction SilentlyContinue | Select-Object -First 1
      if (-not $first) {
        $first = Get-ChildItem -Path $root -Recurse -Filter *.slnx -File -ErrorAction SilentlyContinue | Select-Object -First 1
      }
      if ($first) { $SolutionPath = $first.FullName }
    }
  }
}

if (-not $SolutionPath) {
  Write-Error "No .slnx solution found. Pass the path as a parameter."
  Open-ErrorCover
  exit 1
}

Write-Host "Using solution: $SolutionPath"

# Create output dirs
$output = Join-Path $PSScriptRoot 'TestResults'
$covdir = Join-Path $output 'coverage'
$reportdir = Join-Path $output 'CoverageReport'

New-Item -ItemType Directory -Path $output,$covdir,$reportdir -Force | Out-Null

# Parse projects from solution file — suporta .slnx (XML) e .sln (legado)
$projPaths = @()
$solDir = Split-Path -Path $SolutionPath -Parent

if ($SolutionPath -match '\.slnx$') {
  # Formato .slnx: XML com elementos <Project Path="..."/>
  [xml]$slnx = Get-Content $SolutionPath -Raw
  $nodes = $slnx.SelectNodes('//*[local-name()="Project"][@Path]')
  foreach ($node in $nodes) {
    $rel = $node.GetAttribute('Path')
    if ($rel -match '\.csproj$') {
      $full = Join-Path $solDir $rel
      $resolved = Resolve-Path -Path $full -ErrorAction SilentlyContinue
      if ($resolved) { $projPaths += $resolved.Path } else { $projPaths += $full }
    }
  }
} else {
  # Formato .sln legado: linhas Project("{...}") = "Name", "path\to\proj.csproj", "{guid}"
  $projLines = Get-Content $SolutionPath | Where-Object { $_ -match 'Project\(' }
  foreach ($line in $projLines) {
    if ($line -match 'Project\([^\)]+\)\s*=\s*"[^"]+",\s*"([^"]+\.csproj)"') {
      $rel = $Matches[1]
      $full = Join-Path $solDir $rel
      $resolved = Resolve-Path -Path $full -ErrorAction SilentlyContinue
      if ($resolved) { $projPaths += $resolved.Path } else { $projPaths += (Join-Path $solDir $rel) }
    }
  }
}

if (-not $projPaths) {
  Write-Host "Extracted projects: (no .csproj projects found in the solution)"
} else {
  Write-Host "Extracted projects:`n$($projPaths -join "`n")"
}

# Run tests for projects with 'Tests' in path
foreach ($proj in $projPaths) {
  if ($proj -match 'Tests') {
    Write-Host "--------------------------------------------------"
    Write-Host "Running tests (Debug): $proj"
    Emit-Beep
    # dotnet test $proj --configuration Debug --collect:"XPlat Code Coverage" --settings "$PSScriptRoot\.runsettings"
    dotnet test $proj --configuration $Configuration --collect:"XPlat Code Coverage" --settings "$PSScriptRoot\.runsettings"

    $projDir = Split-Path -Path $proj -Parent
    Emit-Beep
    # Buscar quaisquer arquivos de cobertura gerados (cobertura/opencover/etc.).
    # Usar curinga 'coverage*.xml' para cobrir formatos diferentes produzidos por collectors.
    $testResults = Get-ChildItem -Path $projDir -Recurse -Filter 'coverage*.xml' -File -ErrorAction SilentlyContinue
    foreach ($file in $testResults) {
      Write-Host "Copying: $($file.FullName)"
      Emit-Beep -Frequency 800 -Duration 160
      $safeProjDir = ($projDir -replace '[\\/:]','_')
      $destName = "$safeProjDir`_$($file.Name)"
      Copy-Item -Path $file.FullName -Destination (Join-Path $covdir $destName) -Force
    }
  }
}

# Check for coverage files
# Procurar por qualquer arquivo de cobertura copiado (suportando cobertura/opencover/cobertura)
$covFiles = Get-ChildItem -Path $covdir -Filter '*coverage*.xml' -File -ErrorAction SilentlyContinue
if (-not $covFiles) {
  Write-Host "No coverage files found. Aborting report."
  Play-FinalRing
  exit 0
}

# Generate report
if (-not (Get-Command reportgenerator -ErrorAction SilentlyContinue)) {
  Write-Host "ReportGenerator not found. Install with: dotnet tool install -g dotnet-reportgenerator-globaltool"
  Open-ErrorCover
  exit 1
}

 Emit-Beep -Frequency 700 -Duration 200
 reportgenerator -reports:"$covdir\*coverage*.xml" -targetdir:"$reportdir" -reporttypes:Html
# Remove generated API files that should not be included in coverage reports
# (Some tools generate per-API HTML pages such as API_Generated.html for
# Microsoft.AspNetCore.OpenApi.Generated — remove those from the report.)
try {
  $removePatterns = @('API_Generated.html','*Microsoft.AspNetCore.OpenApi.Generated*.html')
  foreach ($pattern in $removePatterns) {
    $found = Get-ChildItem -Path $reportdir -Recurse -Filter $pattern -File -ErrorAction SilentlyContinue
    foreach ($f in $found) {
      Write-Host "Removing generated coverage file (excluded): $($f.FullName)"
      Remove-Item -Path $f.FullName -Force -ErrorAction SilentlyContinue
    }
  }

  # Also remove simple references (hrefs or text) to those files from other HTML pages
  $htmlFiles = Get-ChildItem -Path $reportdir -Recurse -Include *.html -File -ErrorAction SilentlyContinue
  foreach ($hf in $htmlFiles) {
    $content = Get-Content $hf.FullName -Raw -ErrorAction SilentlyContinue
      if ($null -ne $content -and ($content -match 'API_Generated.html' -or $content -match 'Microsoft.AspNetCore.OpenApi.Generated')) {
      $new = $content -replace 'href="[^"]*API_Generated.html"','' -replace 'API_Generated.html','' -replace 'Microsoft.AspNetCore.OpenApi.Generated',''
      Set-Content -Path $hf.FullName -Value $new -Encoding UTF8
      Write-Host "Cleaned references in: $($hf.FullName)"
    }
  }
} catch {
  Write-Warning "Failed to remove generated files from report: $($_.Exception.Message)"
}

# Tentar abrir o relatório HTML gerado automaticamente (Windows)
$indexPath = Join-Path $reportdir 'index.html'
if (Test-Path $indexPath) {
  try {
    Emit-Beep -Frequency 1000 -Duration 200
    Start-Process -FilePath $indexPath -ErrorAction Stop
    Write-Host "Opening report: $indexPath"
  } catch {
    Write-Warning "Failed to open report automatically: $($_.Exception.Message)"
    Write-Host "You can open manually: $indexPath"
  }
} else {
  Write-Warning "Report file not found: $indexPath"
}

Write-Host "Done. Results in: $output"
Play-FinalRing
exit 0
